   730→/// Furlough a Heat - change status or rename
   731→///
   732→/// Updates heat status (racing/stabled) and/or silks.
   733→/// At least one change must be requested.
   734→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
   735→    // Validate at least one option provided
   736→    if !args.racing && !args.stabled && args.silks.is_none() {
   737→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
   738→    }
   739→
   740→    // Validate racing/stabled mutual exclusivity
   741→    if args.racing && args.stabled {
   742→        return Err("Cannot specify both --racing and --stabled".to_string());
   743→    }
   744→
   745→    // Validate silks if provided
   746→    if let Some(ref silks) = args.silks {
   747→        if !zjjrg_is_kebab_case(silks) {
   748→            return Err(format!("silks must be kebab-case, got '{}'", silks));
   749→        }
   750→    }
   751→
   752→    // Parse and normalize firemark
   753→    let firemark = Firemark::jjrf_parse(&args.firemark)
   754→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   755→    let firemark_key = firemark.jjrf_display();
   756→
   757→    // Verify Heat exists and check status
   758→    {
   759→        let heat = gallops.heats.get(&firemark_key)
   760→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   761→
   762→        // Check not retired (terminal state)
   763→        if heat.status == jjrg_HeatStatus::Retired {
   764→            return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
   765→        }
   766→
   767→        // Validate racing/stabled request
   768→        if args.racing && heat.status == jjrg_HeatStatus::Racing {
   769→            return Err(format!("Heat '{}' is already racing", firemark_key));
   770→        }
   771→        if args.stabled && heat.status == jjrg_HeatStatus::Stabled {
   772→            return Err(format!("Heat '{}' is already stabled", firemark_key));
   773→        }
   774→    }
   775→
   776→    // Apply status change if requested
   777→    if args.racing {
   778→        // Set status to racing
   779→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
   780→
   781→        // Move heat to front of heats object (index 0) to prioritize it
   782→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
   783→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
   784→        }
   785→    } else if args.stabled {
   786→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
   787→    }
   788→
   789→    // Apply silks change if requested
   790→    if let Some(silks) = args.silks {
   791→        gallops.heats.get_mut(&firemark_key).unwrap().silks = silks;
   792→    }
   793→
   794→    Ok(())
   795→}
