    14→/// Increment a base64 seed string (with carry)
    15→/// Works for both 2-char (heat) and 3-char (pace) seeds
    16→#[allow(dead_code)]
    17→pub(crate) fn zjjrg_increment_seed(seed: &str) -> String {
    18→    let mut chars: Vec<u8> = seed.bytes().collect();
    19→    let mut carry = true;
    20→
    21→    // Process from right to left
    22→    for i in (0..chars.len()).rev() {
    23→        if !carry {
    24→            break;
    25→        }
    26→
    27→        // Find current position in charset
    28→        let pos = JJRF_CHARSET.iter().position(|&c| c == chars[i]).unwrap_or(0);
    29→
    30→        if pos == 63 {
    31→            // Wrap around
    32→            chars[i] = JJRF_CHARSET[0];
    33→            // carry remains true
    34→        } else {
    35→            chars[i] = JJRF_CHARSET[pos + 1];
    36→            carry = false;
    37→        }
    38→    }
    39→
    40→    String::from_utf8(chars).unwrap_or_else(|_| seed.to_string())
    41→}
