    43→/// Capture current commit SHA
    44→///
    45→/// Runs `git rev-parse --short=N HEAD` where N is derived from JJRG_UNKNOWN_COMMIT length.
    46→/// Returns JJRG_UNKNOWN_COMMIT on error (e.g., not in a git repo).
    47→pub fn jjrg_capture_commit_sha() -> String {
    48→    use std::process::Command;
    49→
    50→    let short_arg = format!("--short={}", JJRG_UNKNOWN_COMMIT.len());
    51→    match Command::new("git")
    52→        .args(["rev-parse", &short_arg, "HEAD"])
    53→        .output()
    54→    {
    55→        Ok(output) if output.status.success() => {
    56→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    57→        }
    58→        _ => JJRG_UNKNOWN_COMMIT.to_string(),
    59→    }
    60→}
