     5→//! Notch and Chalk - Steeplechase commit formatting
     6→//!
     7→//! Provides message formatting for JJ-aware git commits that record session history:
     8→//! - jjx_notch: Standard commit with heat/pace context prefix
     9→//! - jjx_chalk: Empty commit marking a steeplechase event (pace-level)
    10→//! - Heat-level commits: nominate, slate, rail, tally, draft, retire
    11→//!
    12→//! Commit format: `jjb:HALLMARK:IDENTITY:ACTION: message`
    13→//! - HALLMARK: Version identifier (NNNN or NNNN-xxxxxxx)
    14→//! - IDENTITY: ₢CORONET for pace-level, ₣FIREMARK for heat-level
    15→//! - ACTION: Single letter code (required for all commits)
    16→//!
    17→//! The actual commit execution is handled by vorc_commit in the vok crate.
    18→//! This module exports formatting functions that the CLI handlers use.
    19→
    20→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_CORONET_PREFIX as CORONET_PREFIX, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX};
    21→use std::fs;
    22→use std::process::Command;
    23→
    24→/// Commit message prefix
    25→pub const JJRN_COMMIT_PREFIX: &str = "jjb";
    26→
    27→/// Get hallmark for commit message versioning
    28→///
    29→/// Source logic:
    30→/// 1. Try `.vvk/vvbf_brand.json` → if exists, use `vvbh_hallmark` (4 digits)
    31→/// 2. If missing (Kit Forge) → read `Tools/vok/vov_veiled/vovr_registry.json`,
    32→///    find max hallmark, get `git rev-parse --short HEAD`, format as `{hallmark}-{commit}`
    33→fn zjjrn_get_hallmark() -> String {
    34→    // Try reading brand file
    35→    if let Ok(brand_content) = fs::read_to_string(".vvk/vvbf_brand.json") {
    36→        if let Ok(brand_json) = serde_json::from_str::<serde_json::Value>(&brand_content) {
    37→            if let Some(hallmark) = brand_json.get("vvbh_hallmark") {
    38→                if let Some(hallmark_str) = hallmark.as_str() {
    39→                    return hallmark_str.to_string();
    40→                }
    41→            }
    42→        }
    43→    }
    44→
    45→    // Fallback: Kit Forge mode (read registry + git HEAD)
    46→    let mut max_hallmark = 0u32;
    47→    if let Ok(registry_content) = fs::read_to_string("Tools/vok/vov_veiled/vovr_registry.json") {
    48→        if let Ok(registry_json) = serde_json::from_str::<serde_json::Value>(&registry_content) {
    49→            if let Some(hallmarks) = registry_json.get("hallmarks").and_then(|v| v.as_object()) {
    50→                for key in hallmarks.keys() {
    51→                    if let Ok(num) = key.parse::<u32>() {
    52→                        max_hallmark = max_hallmark.max(num);
    53→                    }
    54→                }
    55→            }
    56→        }
    57→    }
    58→
    59→    // Get short commit hash
    60→    let git_output = Command::new("git")
    61→        .args(["rev-parse", "--short", "HEAD"])
    62→        .output();
    63→
    64→    let commit_hash = if let Ok(output) = git_output {
    65→        if output.status.success() {
    66→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    67→        } else {
    68→            "0000000".to_string()
    69→        }
    70→    } else {
    71→        "0000000".to_string()
    72→    };
    73→
    74→    format!("{:04}-{}", max_hallmark, commit_hash)
    75→}
    76→
    77→/// Pace-level chalk markers (single-letter codes)
    78→/// - A = APPROACH: proposed approach before work begins
    79→/// - W = WRAP: pace completion summary
    80→/// - F = FLY: autonomous execution began (bridled pace)
    81→/// - d = discussion: significant decision (lowercase, can be heat-level too)
    82→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    83→pub enum jjrn_ChalkMarker {
    84→    Approach,
    85→    Wrap,
    86→    Fly,
    87→    Discussion,
    88→}
    89→
    90→impl jjrn_ChalkMarker {
    91→    /// Parse marker from string (accepts both single letter and full word)
    92→    pub fn jjrn_parse(s: &str) -> Result<Self, String> {
    93→        match s {
    94→            "A" | "a" | "APPROACH" | "approach" | "Approach" => Ok(jjrn_ChalkMarker::Approach),
    95→            "W" | "w" | "WRAP" | "wrap" | "Wrap" => Ok(jjrn_ChalkMarker::Wrap),
    96→            "F" | "f" | "FLY" | "fly" | "Fly" => Ok(jjrn_ChalkMarker::Fly),
    97→            "d" | "D" | "DISCUSSION" | "discussion" | "Discussion" => Ok(jjrn_ChalkMarker::Discussion),
    98→            _ => Err(format!(
    99→                "Invalid marker type '{}'. Valid: A(pproach), W(rap), F(ly), d(iscussion)",
   100→                s
   101→            )),
   102→        }
   103→    }
   104→
   105→    /// Get single-letter code for commit message
   106→    pub fn jjrn_code(&self) -> char {
   107→        match self {
   108→            jjrn_ChalkMarker::Approach => 'A',
   109→            jjrn_ChalkMarker::Wrap => 'W',
   110→            jjrn_ChalkMarker::Fly => 'F',
   111→            jjrn_ChalkMarker::Discussion => 'd',
   112→        }
   113→    }
   114→
   115→    /// Get full display string for the marker (for user-facing output)
   116→    pub fn jjrn_as_str(&self) -> &'static str {
   117→        match self {
   118→            jjrn_ChalkMarker::Approach => "APPROACH",
   119→            jjrn_ChalkMarker::Wrap => "WRAP",
   120→            jjrn_ChalkMarker::Fly => "FLY",
   121→            jjrn_ChalkMarker::Discussion => "discussion",
   122→        }
   123→    }
   124→
   125→    /// Returns true if this marker type requires a pace to be specified
   126→    pub fn jjrn_requires_pace(&self) -> bool {
   127→        match self {
   128→            jjrn_ChalkMarker::Approach | jjrn_ChalkMarker::Wrap | jjrn_ChalkMarker::Fly => true,
   129→            jjrn_ChalkMarker::Discussion => false,
   130→        }
   131→    }
   132→}
   133→
   134→/// Heat-level action codes (single-letter codes)
   135→/// - N = Nominate: create new heat
   136→/// - S = Slate: add new pace
   137→/// - r = rail: reorder paces (lowercase)
   138→/// - T = Tally: add tack to pace
   139→/// - D = Draft: move pace between heats (uppercase, rare)
   140→/// - R = Retire: archive heat (uppercase)
   141→/// - f = furlough: change heat status or rename (lowercase)
   142→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
   143→pub enum jjrn_HeatAction {
   144→    Nominate,
   145→    Slate,
   146→    Rail,
   147→    Tally,
   148→    Draft,
   149→    Retire,
   150→    Furlough,
   151→}
   152→
   153→impl jjrn_HeatAction {
   154→    /// Get single-letter code for commit message
   155→    pub fn jjrn_code(&self) -> char {
   156→        match self {
   157→            jjrn_HeatAction::Nominate => 'N',
   158→            jjrn_HeatAction::Slate => 'S',
   159→            jjrn_HeatAction::Rail => 'r',
   160→            jjrn_HeatAction::Tally => 'T',
   161→            jjrn_HeatAction::Draft => 'D',
   162→            jjrn_HeatAction::Retire => 'R',
   163→            jjrn_HeatAction::Furlough => 'f',
   164→        }
   165→    }
   166→
   167→    /// Get full display string (for user-facing output)
   168→    pub fn jjrn_as_str(&self) -> &'static str {
   169→        match self {
   170→            jjrn_HeatAction::Nominate => "nominate",
   171→            jjrn_HeatAction::Slate => "slate",
   172→            jjrn_HeatAction::Rail => "rail",
   173→            jjrn_HeatAction::Tally => "tally",
   174→            jjrn_HeatAction::Draft => "draft",
   175→            jjrn_HeatAction::Retire => "retire",
   176→            jjrn_HeatAction::Furlough => "furlough",
   177→        }
   178→    }
   179→}
   180→
   181→/// Format the notch prefix: jjb:HALLMARK:₢CORONET:n:
   182→///
   183→/// Returns the prefix string to prepend to commit messages for JJ-aware commits.
   184→/// The coronet provides full context (embeds parent firemark).
   185→pub fn jjrn_format_notch_prefix(coronet: &Coronet) -> String {
   186→    let hallmark = zjjrn_get_hallmark();
   187→    format!(
   188→        "{}:{}:{}{}:n: ",
   189→        JJRN_COMMIT_PREFIX,
   190→        hallmark,
   191→        CORONET_PREFIX,
   192→        coronet.jjrf_as_str(),
   193→    )
   194→}
   195→
   196→/// Format the chalk message: jjb:HALLMARK:₢CORONET:X: description
   197→///
   198→/// Returns the full commit message for a chalk (steeplechase marker) commit.
   199→pub fn jjrn_format_chalk_message(coronet: &Coronet, marker: jjrn_ChalkMarker, description: &str) -> String {
   200→    let hallmark = zjjrn_get_hallmark();
   201→    format!(
   202→        "{}:{}:{}{}:{}: {}",
   203→        JJRN_COMMIT_PREFIX,
   204→        hallmark,
   205→        CORONET_PREFIX,
   206→        coronet.jjrf_as_str(),
   207→        marker.jjrn_code(),
   208→        description
   209→    )
   210→}
   211→
   212→/// Format a heat-level discussion message (no pace context): jjb:HALLMARK:₣XX:d: description
   213→pub fn jjrn_format_heat_discussion(firemark: &Firemark, description: &str) -> String {
   214→    let hallmark = zjjrn_get_hallmark();
   215→    format!(
   216→        "{}:{}:{}{}:d: {}",
   217→        JJRN_COMMIT_PREFIX,
   218→        hallmark,
   219→        FIREMARK_PREFIX,
   220→        firemark.jjrf_as_str(),
   221→        description
   222→    )
   223→}
   224→
   225→/// Format a heat-level action message: jjb:HALLMARK:₣XX:X: description
   226→///
   227→/// Used for nominate, slate, rail, tally, draft, retire operations.
   228→pub fn jjrn_format_heat_message(firemark: &Firemark, action: jjrn_HeatAction, description: &str) -> String {
   229→    let hallmark = zjjrn_get_hallmark();
   230→    format!(
